import React, { useState, useCallback, useEffect } from 'react';
import { UrlInput } from './components/UrlInput';
import { BookmarkList } from './components/BookmarkList';
import { Header } from './components/Header';
import { ApiKeySetup } from './components/ApiKeySetup';
import { generateBookmarkDetails, ApiKeyError } from './services/geminiService';
import { Bookmark } from './types';
import { v4 as uuidv4 } from 'uuid';

const AI_BOOKMARKS_STORAGE_KEY = 'ai-bookmark-manager-bookmarks';
const THEME_STORAGE_KEY = 'ai-bookmark-manager-theme';

// Helper function to remove UTM tracking parameters from a URL
const stripUtmParams = (urlString: string): string => {
  if (!urlString || !urlString.includes('utm_')) return urlString;
  try {
    const url = new URL(urlString);
    const params = url.searchParams;
    const keysToDelete = Array.from(params.keys()).filter(key => key.startsWith('utm_'));
    if (keysToDelete.length > 0) {
        keysToDelete.forEach(key => params.delete(key));
        return url.toString();
    }
    return urlString; 
  } catch (e) {
    return urlString;
  }
};

const App: React.FC = () => {
  const [bookmarks, setBookmarks] = useState<Bookmark[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [hasKey, setHasKey] = useState<boolean | null>(null);

  // Initialize dark mode from localStorage or system preference
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    try {
      const storedTheme = localStorage.getItem(THEME_STORAGE_KEY);
      if (storedTheme !== null) {
        return storedTheme === 'dark';
      }
      return window.matchMedia('(prefers-color-scheme: dark)').matches;
    } catch (e) {
      return window.matchMedia('(prefers-color-scheme: dark)').matches;
    }
  });

  // Check if API key is already selected on mount
  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore - aistudio is injected environment
      if (window.aistudio?.hasSelectedApiKey) {
        // @ts-ignore
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasKey(selected);
      } else {
        // Fallback or development environment
        setHasKey(true);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    // @ts-ignore
    if (window.aistudio?.openSelectKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
      // Guidelines state: proceed assuming success after triggering dialog
      setHasKey(true); 
    }
  };

  // Load bookmarks from localStorage on initial mount
  useEffect(() => {
    const storedBookmarks = localStorage.getItem(AI_BOOKMARKS_STORAGE_KEY);
    if (storedBookmarks) {
      try {
        const parsedBookmarks = JSON.parse(storedBookmarks);
        const migratedBookmarks = parsedBookmarks.map((b: any) => ({
            ...b,
            id: b.id || uuidv4(),
            status: b.status === 'processing' ? 'error' : (b.status || 'done'),
            createdAt: b.createdAt || new Date().toISOString(),
        })) as Bookmark[];
        setBookmarks(migratedBookmarks);
      } catch (e) {
        console.error("Failed to parse stored bookmarks:", e);
        localStorage.removeItem(AI_BOOKMARKS_STORAGE_KEY);
      }
    }
  }, []);

  // Save bookmarks to localStorage
  useEffect(() => {
    localStorage.setItem(AI_BOOKMARKS_STORAGE_KEY, JSON.stringify(bookmarks));
  }, [bookmarks]);

  // Apply dark mode
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem(THEME_STORAGE_KEY, isDarkMode ? 'dark' : 'light');
  }, [isDarkMode]);

  const toggleDarkMode = useCallback(() => {
    setIsDarkMode(prevMode => !prevMode);
  }, []);

  const handleProcessUrls = useCallback(async (urlData: { url: string; addDate?: string }[]) => {
    if (!urlData.length) return;

    setIsLoading(true);
    setError(null);

    const existingUrls = new Set(bookmarks.filter(b => b.status !== 'error').map(b => b.url));
    const uniqueUrlData: { url: string; addDate?: string }[] = [];

    for (const data of urlData) {
        const cleanedUrl = stripUtmParams(data.url);
        if (!existingUrls.has(cleanedUrl)) {
            uniqueUrlData.push({ ...data, url: cleanedUrl });
            existingUrls.add(cleanedUrl);
        }
    }

    if (uniqueUrlData.length === 0) {
      setIsLoading(false);
      return;
    }

    const newBookmarks: Bookmark[] = uniqueUrlData.map(data => ({
      id: uuidv4(),
      url: data.url,
      title: 'Processing...',
      summary: '',
      keywords: [],
      status: 'processing',
      createdAt: data.addDate || new Date().toISOString(),
    }));

    setBookmarks(prev => [...prev, ...newBookmarks]);

    for (const bookmark of newBookmarks) {
      try {
        const details = await generateBookmarkDetails(bookmark.url);
        const isWarning = !details.summary || details.keywords.length === 0;

        setBookmarks(prev => prev.map(b => 
            b.id === bookmark.id 
            ? {
                ...bookmark,
                title: details.title,
                summary: details.summary || "AI summary generation failed.",
                keywords: details.keywords,
                sources: details.sources,
                createdAt: details.publicationDate ? new Date(details.publicationDate).toISOString() : bookmark.createdAt,
                status: isWarning ? 'warning' : 'done',
              }
            : b
        ));
      } catch (e: any) {
        const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred.';

        // Handle mandatory key re-selection on specific errors
        if (errorMessage.includes('Requested entity was not found') || errorMessage.includes('API key not valid')) {
          setError("Session expired or API key invalid. Please re-select your key.");
          setHasKey(false);
          setBookmarks(prev => prev.filter(b => b.status !== 'processing'));
          setIsLoading(false);
          return;
        }

        setBookmarks(prev => prev.map(b => 
            b.id === bookmark.id
            ? {
                ...bookmark,
                title: 'Error processing URL',
                summary: errorMessage,
                status: 'error' as const,
              }
            : b
        ));
      }

      // Respect rate limits
      if (newBookmarks.indexOf(bookmark) < newBookmarks.length - 1) {
          await new Promise(resolve => setTimeout(resolve, 1100));
      }
    }

    setIsLoading(false);
  }, [bookmarks]);

  const handleUpdateBookmark = useCallback((updatedBookmark: Bookmark) => {
    setBookmarks(prev => prev.map(b => (b.id === updatedBookmark.id ? updatedBookmark : b)));
  }, []);

  const handleDeleteBookmark = useCallback((id: string) => {
    setBookmarks(prev => prev.filter(b => b.id !== id));
  }, []);

  const handleClearAll = useCallback(() => {
    setBookmarks([]);
  }, []);

  const handleRetryBookmark = useCallback(async (bookmarkId: string) => {
    const bookmarkToRetry = bookmarks.find(b => b.id === bookmarkId);
    if (!bookmarkToRetry) return;

    const cleanedUrl = stripUtmParams(bookmarkToRetry.url);
    setBookmarks(prev => prev.map(b => b.id === bookmarkId ? { ...b, status: 'processing', title: 'Retrying...' } : b));
    setError(null);

    try {
      const details = await generateBookmarkDetails(cleanedUrl);
      const isWarning = !details.summary || details.keywords.length === 0;

      setBookmarks(prev => prev.map(b =>
          b.id === bookmarkId
            ? {
                ...bookmarkToRetry,
                url: cleanedUrl,
                title: details.title,
                summary: details.summary || "AI summary generation failed.",
                keywords: details.keywords,
                sources: details.sources,
                createdAt: details.publicationDate ? new Date(details.publicationDate).toISOString() : bookmarkToRetry.createdAt,
                status: isWarning ? 'warning' : 'done',
              }
            : b
      ));
    } catch (e: any) {
        const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred.';
        if (errorMessage.includes('Requested entity was not found') || errorMessage.includes('API key not valid')) {
            setHasKey(false);
            setError("API key invalid. Please re-select.");
            return;
        }
        setBookmarks(prev => prev.map(b => b.id === bookmarkId ? { ...b, status: 'error' as const, summary: errorMessage, title: 'Retry failed' } : b));
    }
  }, [bookmarks]);

  if (hasKey === false) {
    return <ApiKeySetup onSelectKey={handleSelectKey} error={error} />;
  }

  // Prevent UI flicker while checking initial state
  if (hasKey === null) return null;

  return (
    <div className="min-h-screen text-slate-800 dark:text-slate-200 font-sans">
      <Header 
        bookmarks={bookmarks} 
        onClearAll={handleClearAll} 
        isDarkMode={isDarkMode}
        onToggleDarkMode={toggleDarkMode}
      />
      <main className="container mx-auto p-4 md:p-8">
        <div className="max-w-4xl mx-auto">
          <UrlInput onProcess={handleProcessUrls} isLoading={isLoading} />
          {error && <div className="mt-4 text-center text-red-500 bg-red-100 dark:bg-red-900/50 p-3 rounded-lg" role="alert">{error}</div>}
          <BookmarkList
            bookmarks={bookmarks}
            onUpdate={handleUpdateBookmark}
            onDelete={handleDeleteBookmark}
            onRetry={handleRetryBookmark}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

// Custom error to be thrown when API key is invalid
export class ApiKeyError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ApiKeyError';
  }
}

const MAX_RETRIES = 2; 
const INITIAL_BACKOFF_MS = 1500;

function delay(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

export async function generateBookmarkDetails(url: string): Promise<{ 
    title: string; 
    summary: string; 
    keywords: string[]; 
    publicationDate: string | null; 
    sources: { uri: string; title: string }[] 
}> {
    if (!process.env.API_KEY) {
        throw new ApiKeyError("API_KEY environment variable is not set. Please select a key.");
    }

    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
            // Use gemini-3-flash-preview as per guidelines for basic text and search tasks
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            const prompt = `
            Analyze the content of the webpage at: ${url}

            Task:
            1. Use the search tool to extract the site's main content, title, and publication date.
            2. Provide a concise 2-sentence summary and 3-5 relevant keywords.

            Response Format (Return ONLY this JSON object):
            {
              "title": "Page title here",
              "summary": "1-2 sentence summary of content",
              "keywords": ["kw1", "kw2", "kw3"],
              "publicationDate": "ISO 8601 date string or null"
            }
            `;

            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: prompt,
                config: {
                    tools: [{ googleSearch: {} }],
                    temperature: 0.1,
                }
            });

            // CRITICAL FIX: Safely extract text output from response to avoid TypeError on .trim()
            const responseText = response.text || "";
            if (!responseText) {
                const candidate = response.candidates?.[0];
                if (candidate?.finishReason === 'SAFETY') {
                    throw new Error("Content blocked by safety filters.");
                }
                throw new Error("Empty response received from AI. The site might be blocking bots.");
            }

            // Extract grounding chunks for citations/sources
            const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
            const sources = groundingChunks?.map((chunk: any) => {
                if (chunk.web && chunk.web.uri) {
                    return {
                        uri: chunk.web.uri,
                        title: chunk.web.title || chunk.web.uri,
                    };
                }
                return null;
            }).filter((source: any): source is { uri: string; title: string; } => source !== null) || [];

            // Robust JSON extraction to handle search citations or markdown wrapping
            const rawText = responseText.trim();
            const jsonMatch = rawText.match(/```json\s*([\s\S]*?)\s*```/) || 
                            rawText.match(/{[\s\S]*}/);

            const jsonToParse = jsonMatch ? jsonMatch[1] || jsonMatch[0] : rawText;

            try {
                const parsed = JSON.parse(jsonToParse);

                return {
                    title: parsed.title || "Untitled Bookmark",
                    summary: parsed.summary || "No summary available.",
                    keywords: Array.isArray(parsed.keywords) ? parsed.keywords : [],
                    publicationDate: parsed.publicationDate || null,
                    sources,
                };
            } catch (parseError) {
                console.warn("Could not parse JSON from AI response, attempting fallback extraction.", rawText);
                return {
                    title: url.replace(/^https?:\/\//, '').split('/')[0] || "Webpage",
                    summary: responseText.length > 15 ? responseText.substring(0, 150) + "..." : "Summary generation failed.",
                    keywords: [],
                    publicationDate: null,
                    sources,
                };
            }

        } catch (error: any) {
            console.error(`Gemini API Error (Attempt ${attempt + 1}):`, error);
            const errorMessage = error?.message || '';

            // Bubble up specific key errors to trigger UI reset
            if (errorMessage.includes('API key not valid') || errorMessage.includes('Requested entity was not found')) {
                throw error;
            }

            // Exponential backoff for rate limiting
            if (errorMessage.includes('RESOURCE_EXHAUSTED') && attempt < MAX_RETRIES) {
                const waitTime = INITIAL_BACKOFF_MS * Math.pow(2, attempt);
                await delay(waitTime);
                continue;
            }

            if (attempt === MAX_RETRIES) {
                throw new Error(errorMessage || "API request failed after retries.");
            }

            await delay(1000);
        }
    }
    throw new Error("Bookmark details generation failed unexpectedly.");
}

import React, { useState } from 'react';
import { Spinner } from './common/Spinner';

interface UrlInputProps {
  onProcess: (urls: { url: string; addDate?: string }[]) => void;
  isLoading: boolean;
}

export const UrlInput: React.FC<UrlInputProps> = ({ onProcess, isLoading }) => {
  const [text, setText] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Added explicit return type to map to ensure inferred type is consistent for the filter predicate
    const processedUrls = text.split('\n').map((line): { url: string; addDate?: string } | null => {
        const trimmedLine = line.trim();

        // Check for Netscape bookmark format with ADD_DATE (case-insensitive)
        const bookmarkMatch = trimmedLine.match(/<a\s+href="([^"]+)"[^>]*add_date="(\d+)"/i);
        if (bookmarkMatch && bookmarkMatch[1] && bookmarkMatch[2]) {
            const url = bookmarkMatch[1];
            // ADD_DATE is a Unix timestamp in seconds. Convert to milliseconds for Date constructor.
            const addDateTimestamp = parseInt(bookmarkMatch[2], 10) * 1000;
            const addDate = new Date(addDateTimestamp).toISOString();
            return { url, addDate };
        }

        // Fallback for Netscape bookmark format without ADD_DATE
        const hrefMatch = trimmedLine.match(/<a\s+href="([^"]+)"/i);
        if (hrefMatch && hrefMatch[1]) {
            return { url: hrefMatch[1], addDate: undefined };
        }

        // If it's not a bookmark line, filter out other common HTML tags
        // that might be part of a pasted bookmark file.
        if (trimmedLine.startsWith('<')) {
            return null; // Discard tags like <DT>, <H1>, etc.
        }

        // Apply existing cleaning logic for plain text URLs (e.g., from a list)
        const withoutNumber = trimmedLine.replace(/^\d+\s*[.)-]\s+/, '');
        const withoutBullet = withoutNumber.replace(/^[-*]\s+/, '');

        // Ensure we don't return an empty object
        if (withoutBullet.length > 0) {
            return { url: withoutBullet, addDate: undefined };
        }

        return null;
    }).filter((item): item is { url: string; addDate?: string } => item !== null);

    onProcess(processedUrls);
    setText('');
  };

  return (
    <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-lg mb-8">
      <form onSubmit={handleSubmit}>
        <label htmlFor="url-input" className="block text-lg font-medium text-slate-700 dark:text-slate-300 mb-2">
          Import Bookmarks
        </label>
        <p className="text-sm text-slate-500 dark:text-slate-400 mb-4">
          Paste one URL per line or the content of a bookmarks HTML file. The AI will generate a title, summary, and keywords for each.
        </p>
        <textarea
          id="url-input"
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder={"https://example.com/article-1\nhttps://anothersite.org/important-info\nOr paste content from a bookmarks.html file..."}
          rows={6}
          className="w-full p-3 bg-slate-100 dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
          disabled={isLoading}
        />
        <button
          type="submit"
          disabled={isLoading || !text.trim()}
          className="mt-4 w-full flex justify-center items-center px-6 py-3 border border-transparent text-base font-medium rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:bg-slate-400 dark:disabled:bg-slate-600 disabled:cursor-not-allowed transition-all"
        >
          {isLoading ? (
            <>
              <Spinner className="h-5 w-5 mr-3 text-white" />
              Processing...
            </>
          ) : (
            'Generate Details'
          )}
        </button>
      </form>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

// Custom error to be thrown when API key is invalid
export class ApiKeyError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ApiKeyError';
  }
}

const MAX_RETRIES = 2; 
const INITIAL_BACKOFF_MS = 2000;

function delay(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

export interface BookmarkResult {
    url: string;
    title: string; 
    summary: string; 
    keywords: string[]; 
    publicationDate: string | null; 
    sources: { uri: string; title: string }[] 
}

/**
 * Generates details for a batch of URLs in a single API call to optimize quota usage.
 * Recommended batch size: 4 URLs to balance accuracy, grounding capability and efficiency.
 */
export async function generateBookmarksBatch(urls: string[]): Promise<BookmarkResult[]> {
    if (!process.env.API_KEY) {
        throw new ApiKeyError("API_KEY environment variable is not set. Please select a key.");
    }

    if (urls.length === 0) return [];

    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            const prompt = `
            Analyze the content for the following list of URLs:
            ${urls.map((url, i) => `${i + 1}. ${url}`).join('\n')}

            Task:
            1. For EACH URL, use search grounding to find the actual page content, site title, and publication date if available.
            2. Provide a 2-sentence summary and 3-5 keywords for each.
            3. Ensure the response is a JSON array of objects, one for each input URL in the EXACT same order.

            Response Format (Return ONLY this JSON array):
            [
              {
                "url": "original_url_here",
                "title": "Page title here",
                "summary": "1-2 sentence summary",
                "keywords": ["kw1", "kw2"],
                "publicationDate": "ISO 8601 date string or null"
              },
              ...
            ]
            `;

            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: prompt,
                config: {
                    tools: [{ googleSearch: {} }],
                    temperature: 0.1,
                    responseMimeType: "application/json"
                }
            });

            const responseText = response.text || "";
            if (!responseText) {
                const candidate = response.candidates?.[0];
                if (candidate?.finishReason === 'SAFETY') {
                    throw new Error("Content blocked by safety filters.");
                }
                throw new Error("Empty response received from AI.");
            }

            // Extract grounding chunks for citations/sources
            const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
            const sources = groundingChunks.map((chunk: any) => {
                if (chunk.web && chunk.web.uri) {
                    return {
                        uri: chunk.web.uri,
                        title: chunk.web.title || chunk.web.uri,
                    };
                }
                return null;
            }).filter((s): s is { uri: string; title: string } => s !== null);

            let results: any[];
            try {
                // Remove potential markdown wrappers if they exist despite responseMimeType
                const cleanJson = responseText.trim().replace(/^```json\s*/i, '').replace(/\s*```$/i, '');
                results = JSON.parse(cleanJson);
                if (!Array.isArray(results)) {
                    throw new Error("AI response is not an array");
                }
            } catch (e) {
                console.error("Failed to parse AI JSON:", responseText);
                throw new Error("Failed to parse batch JSON response");
            }

            // Map results back to the expected format, matching URLs as closely as possible
            return urls.map(originalUrl => {
                const found = results.find(r => 
                    r.url?.toLowerCase() === originalUrl.toLowerCase() || 
                    r.url?.toLowerCase().includes(originalUrl.toLowerCase()) || 
                    originalUrl.toLowerCase().includes(r.url?.toLowerCase())
                );

                const fallbackTitle = originalUrl.replace(/^https?:\/\//, '').split('/')[0] || "Webpage";

                return {
                    url: originalUrl,
                    title: found?.title || fallbackTitle,
                    summary: found?.summary || "Summary generation failed.",
                    keywords: Array.isArray(found?.keywords) ? found.keywords : [],
                    publicationDate: found?.publicationDate || null,
                    // Grounding sources are often general to the search session, so we provide them for all items in batch
                    sources: sources.length > 0 ? sources : [], 
                };
            });

        } catch (error: any) {
            console.error(`Gemini API Batch Error (Attempt ${attempt + 1}):`, error);
            const errorMessage = error?.message || '';

            if (errorMessage.includes('API key not valid') || errorMessage.includes('Requested entity was not found')) {
                throw error;
            }

            // Exponential backoff for rate limiting (429)
            if ((errorMessage.includes('RESOURCE_EXHAUSTED') || errorMessage.includes('429')) && attempt < MAX_RETRIES) {
                const waitTime = INITIAL_BACKOFF_MS * Math.pow(2.5, attempt);
                await delay(waitTime);
                continue;
            }

            if (attempt === MAX_RETRIES) {
                throw new Error(errorMessage || "Batch API request failed.");
            }

            await delay(2000);
        }
    }
    throw new Error("Batch processing failed unexpectedly.");
}

/** 
 * Legacy single-URL wrapper that uses the batch logic under the hood 
 * to maintain consistent behavior for retries.
 */
export async function generateBookmarkDetails(url: string): Promise<BookmarkResult> {
    const results = await generateBookmarksBatch([url]);
    if (results.length === 0) throw new Error("No results returned");
    return results[0];
}

