    this.name = 'ApiKeyError';
  }
}

const MAX_RETRIES = 3; 
const INITIAL_BACKOFF_MS = 6000; 

function delay(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

export interface BookmarkResult {
    url: string;
    title: string; 
    summary: string; 
    keywords: string[]; 
    publicationDate: string | null; 
    sources: { uri: string; title: string }[] 
}

/**
 * Generates details for a batch of URLs. 
 * Switched to urlContext tool as it is more efficient for direct link retrieval.
 */
export async function generateBookmarksBatch(urls: string[]): Promise<BookmarkResult[]> {
    if (!process.env.API_KEY) {
        throw new ApiKeyError("API_KEY environment variable is not set.");
    }

    if (urls.length === 0) return [];

    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            const prompt = `
            Analyze the content of the following URLs:
            ${urls.map((url, i) => `${i + 1}. ${url}`).join('\n')}

            CRITICAL INSTRUCTIONS:
            1. Use the urlContext tool to retrieve and read the actual live content of each URL.
            2. Provide a 2-sentence summary of the page's core message.
            3. Identify 3-5 keywords.

            SPECIAL HANDLING FOR TWITTER/X:
            - You MUST fetch the actual tweet text. 
            - Summary: A precise transcription or description of the tweet's content.
            - Keywords: Reuse all hashtags present in the tweet text.
            - Title: "Tweet by [User] (@handle)".

            Format your response as a valid JSON array of objects.
            [
              {
                "url": "original_url",
                "title": "Page/Tweet Title",
                "summary": "The summary content...",
                "keywords": ["tag1", "tag2"],
                "publicationDate": "YYYY-MM-DD"
              }
            ]
            `;

            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: prompt,
                config: {
                    // Using urlContext tool for targeted retrieval as suggested
                    tools: [{ urlContext: {} } as any],
                    temperature: 0.1,
                    responseMimeType: "application/json"
                }
            });

            const responseText = response.text;
            if (!responseText) {
                throw new Error("Empty AI response.");
            }

            // Fallback to groundingMetadata for sources if available
            const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
            const groundingChunks = groundingMetadata?.groundingChunks || [];
            const sources = groundingChunks
                .filter((chunk: any) => chunk.web && chunk.web.uri)
                .map((chunk: any) => ({
                    uri: chunk.web.uri,
                    title: chunk.web.title || chunk.web.uri,
                }));

            let results: any[];
            try {
                results = JSON.parse(responseText.trim());
            } catch (e) {
                console.error("JSON Parse Error:", responseText);
                throw new Error("Invalid response format from AI.");
            }

            return urls.map(originalUrl => {
                const found = results.find(r => 
                    r.url?.toLowerCase().includes(originalUrl.toLowerCase()) || 
                    originalUrl.toLowerCase().includes(r.url?.toLowerCase() || '---')
                );

                let validDate: string | null = null;
                if (found?.publicationDate && typeof found.publicationDate === 'string') {
                    const d = new Date(found.publicationDate);
                    if (!isNaN(d.getTime()) && d.getFullYear() > 1970) {
                        validDate = d.toISOString();
                    }
                }

                return {
                    url: originalUrl,
                    title: found?.title || originalUrl.split('/')[2] || "Untitled",
                    summary: found?.summary || "Summary could not be generated.",
                    keywords: Array.isArray(found?.keywords) ? found.keywords : [],
                    publicationDate: validDate,
                    sources: sources.length > 0 ? sources.slice(0, 5) : [{ uri: originalUrl, title: "Source Content" }],
                };
            });

        } catch (error: any) {
            const message = error?.message || "";
            const isQuotaError = message.includes('429') || message.includes('RESOURCE_EXHAUSTED');

            if (message.includes('API key not valid')) {
                throw new ApiKeyError("API Key invalid.");
            }

            if (isQuotaError && attempt < MAX_RETRIES) {
                // Heavier backoff for grounding tools: 6s, 24s, 96s
                const waitTime = INITIAL_BACKOFF_MS * Math.pow(4, attempt);
                console.warn(`Grounding quota limit hit. Retrying in ${waitTime}ms...`);
                await delay(waitTime);
                continue;
            }

            if (attempt === MAX_RETRIES) throw error;
            await delay(2000);
        }
    }
    throw new Error("Analysis failed after multiple attempts.");
}

export async function generateBookmarkDetails(url: string): Promise<BookmarkResult> {
    const results = await generateBookmarksBatch([url]);
    return results[0];
}

