            [
              {
                "url": "input_url",
                "title": "Title Here",
                "summary": "Summary here...",
                "keywords": ["kw1", "kw2"],
                "publicationDate": "YYYY-MM-DD"
              }
            ]
            `;

            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
