            const isTimeout = message.includes('timed out');

            // Retry on timeout or quota
            if ((isQuotaError || isTimeout) && attempt < MAX_RETRIES) {
                const waitTime = INITIAL_BACKOFF_MS * Math.pow(3, attempt);
                console.warn(`[GeminiService] ${isTimeout ? 'Timeout' : 'Quota limit'} reached. Retrying in ${waitTime}ms...`);
                await delay(waitTime);
                continue;
            }

