import { GoogleGenAI } from "@google/genai";

const MAX_RETRIES = 2; 
const INITIAL_BACKOFF_MS = 5000;
const API_TIMEOUT_MS = 90000; 

function delay(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

export interface BookmarkResult {
    url: string;
    title: string; 
    summary: string; 
    keywords: string[]; 
    publicationDate: string | null; 
    sources: { uri: string; title: string }[] 
}

/**
 * Generates details for a batch of URLs.
 * Dynamically selects between url_context (direct retrieval) and googleSearch (for social media/blocked sites).
 */
export async function generateBookmarksBatch(urls: string[]): Promise<BookmarkResult[]> {
    console.log(`[GeminiService] Called for URLs:`, urls);

    if (!process.env.API_KEY) {
        console.error("[GeminiService] API Key is missing");
        throw new Error("API Key is missing.");
    }

    if (urls.length === 0) return [];

    // Detect if the batch contains Twitter/X links
    const isTwitterBatch = urls.some(u => 
        u.toLowerCase().includes('twitter.com') || 
        u.toLowerCase().includes('x.com')
    );

    console.log(`[GeminiService] Strategy: ${isTwitterBatch ? 'Twitter/GoogleSearch' : 'Standard/UrlContext'}`);

    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            let tools: any[];
            let strategyPrompt: string;

            if (isTwitterBatch) {
                // Strategy A: Google Search for Twitter/X
                tools = [{ googleSearch: {} }];
                strategyPrompt = `
                You are a digital archivist analyzing Twitter/X posts.

                TARGET URLs:
                ${urls.map((url, i) => `${i + 1}. ${url}`).join('\n')}

                TASK:
                1. Use Google Search to find the *actual text content* of the tweets. 
                   - Search for the Tweet ID or URL.
                   - Look for matches in search snippets from x.com, twitter.com, or mirrors/aggregators.
                2. VERIFICATION:
                   - If you cannot find the specific text of the tweet in the search results, return "Content unavailable".
                   - DO NOT guess the content based on the words in the URL slug. 
                   - DO NOT hallucinate.
                3. Title Format: "Tweet by [Author Handle/Name]"
                `;
            } else {
                // Strategy B: url_context for standard websites
                const urlContextLinks = urls.map(url => ({ url }));
                tools = [{ 
                    // @ts-ignore
                    url_context: { links: urlContextLinks } 
                }];
                strategyPrompt = `
                You are a librarian summarizing web pages.

                TARGET URLs:
                ${urls.map((url, i) => `${i + 1}. ${url}`).join('\n')}

                TASK:
                1. Read the page content using the provided tool.
                2. If the tool returns empty content or a "blocked" message, return "Content unavailable".
                3. Summary: A concise 2-sentence summary of the main points.
                4. Title: The actual page title (document.title).
                `;
            }

            const prompt = `
            ${strategyPrompt}

            OUTPUT FORMAT:
            Return ONLY a raw JSON array. Do not include markdown formatting like \`\`\`json.
            [
              {
                "url": "original_url",
                "title": "Title",
                "summary": "Content summary...",
                "keywords": ["tag1", "tag2"],
                "publicationDate": "YYYY-MM-DD"
              }
            ]
            `;

            console.log(`[GeminiService] Attempt ${attempt + 1}: Sending request to model (Timeout: ${API_TIMEOUT_MS}ms).`);

            const timeoutPromise = new Promise<never>((_, reject) => 
                setTimeout(() => reject(new Error(`Request timed out after ${API_TIMEOUT_MS / 1000}s`)), API_TIMEOUT_MS)
            );

            // Use gemini-3-pro-preview for better reasoning and tool use
            const response = await Promise.race([
                ai.models.generateContent({
                    model: "gemini-3-pro-preview",
                    contents: prompt,
                    config: {
                        tools: tools,
                        responseMimeType: "application/json",
                        thinkingConfig: { thinkingBudget: 2048 } // Enable thinking for better search strategy
                    }
                }),
                timeoutPromise
            ]);

            const responseText = response.text;
            console.log(`[GeminiService] Attempt ${attempt + 1}: Response received.`);

            // If response is empty, it might be a safety block or tool failure.
            // Instead of throwing immediately, let's try to construct a fallback result if possible,
            // or throw specific error to trigger retry only if it makes sense.
            if (!responseText) {
                 const finishReason = response.candidates?.[0]?.finishReason;
                 console.warn(`[GeminiService] Empty response. Finish reason: ${finishReason}`);

                 if (finishReason === 'SAFETY') {
                     throw new Error("Content blocked by safety filters.");
                 }
                 throw new Error("Empty AI response received.");
            }

            const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
            const groundingChunks = groundingMetadata?.groundingChunks || [];
            const sources = groundingChunks
                .filter((chunk: any) => chunk.web && chunk.web.uri)
                .map((chunk: any) => ({
                    uri: chunk.web.uri,
                    title: chunk.web.title || chunk.web.uri,
                }));

            let results: any[];
            try {
                // Sanitize markdown code blocks if present
                const sanitizedText = responseText.replace(/```json\n?|```/g, "").trim();
                results = JSON.parse(sanitizedText);
            } catch (e) {
                console.error("[GeminiService] JSON Parse Error. Response text:", responseText);
                throw new Error("Failed to parse analysis results.");
            }

            return urls.map(originalUrl => {
                const found = results.find(r => 
                    r.url?.toLowerCase().includes(originalUrl.toLowerCase()) || 
                    originalUrl.toLowerCase().includes(r.url?.toLowerCase() || '---')
                );

                let validDate: string | null = null;
                if (found?.publicationDate && typeof found.publicationDate === 'string') {
                    const d = new Date(found.publicationDate);
                    if (!isNaN(d.getTime()) && d.getFullYear() > 1970) {
                        validDate = d.toISOString();
                    }
                }

                return {
                    url: originalUrl,
                    title: found?.title || originalUrl.split('/')[2] || "Untitled",
                    summary: found?.summary || "Content unavailable",
                    keywords: Array.isArray(found?.keywords) ? found.keywords : [],
                    publicationDate: validDate,
                    sources: sources.length > 0 ? sources.slice(0, 5) : [{ uri: originalUrl, title: "Source Content" }],
                };
            });

        } catch (error: any) {
            const message = error?.message || "";
            console.warn(`[GeminiService] Error on attempt ${attempt + 1}:`, message);

            const isQuotaError = message.includes('429') || message.includes('RESOURCE_EXHAUSTED');
            const isTimeout = message.includes('timed out');
            const isSafety = message.includes('safety filters');

            // Don't retry on safety blocks, just fail immediately
            if (isSafety) throw error;

            if (attempt < MAX_RETRIES) {
                let waitTime = INITIAL_BACKOFF_MS * Math.pow(2, attempt); // Reduced backoff multiplier for snappier retries
                if (isTimeout) waitTime = 2000; 

                console.warn(`[GeminiService] Retrying in ${waitTime}ms...`);
                await delay(waitTime);
                continue;
            }

            // If we failed after retries, return a "failed" object instead of throwing if possible,
            // BUT the App.tsx expects the whole batch to fail or succeed. 
            // Since we process 1 by 1 in App.tsx, throwing here marks it as Error in UI, which is correct.
            throw error;
        }
    }
    throw new Error("Processing failed after several attempts.");
}

